            <path d={describeArc(center, center, radius - 4, startAngle, currentProgressAngle)} fill="none" stroke="url(#arcGradient)" strokeWidth="7" strokeLinecap="round" className="transition-none" style={{ filter: 'url(#needleGlow)' }} />
